const html = $input.first().json.data;

let title = '';
let tags = [];

// JSON-LD parse
const jsonLdMatch = html.match(/<script type="application\/ld\+json">([\s\S]*?)<\/script>/);
if (jsonLdMatch) {
  try {
    const ld = JSON.parse(jsonLdMatch[1]);
    if (ld.name) title = ld.name;
    if (ld.keywords) tags = ld.keywords.split(',').map(t => t.trim()).filter(Boolean);
  } catch(e) {}
}

// og:title fallback
if (!title) {
  const ogMatch = html.match(/<meta property="og:title" content="([^"]+)"/);
  if (ogMatch) title = ogMatch[1].replace(/ \| Etsy.*$/, '').trim();
}

// H1 fallback
if (!title) {
  const h1Match = html.match(/<h1[^>]*>([^<]+)<\/h1>/);
  if (h1Match) title = h1Match[1].trim();
}

// tags fallback
if (!tags.length) {
  const tagsMatch = html.match(/"tags"\s*:\s*\[([^\]]+)\]/);
  if (tagsMatch) {
    tags = tagsMatch[1].match(/"([^"]+)"/g)?.map(t => t.replace(/"/g, '')) || [];
  }
}

if (!title) {
  throw new Error('Title bulunamadı. Etsy sayfası bot koruması yapıyor olabilir.');
}

return [{ json: { title, tags } }];

const gptResponse = $input.first().json.message.content;
const originalTitle = $('Parse Title & Tags').first().json.title;
const originalTags = $('Parse Title & Tags').first().json.tags;

let sets = [];
try {
  const clean = gptResponse.replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(clean);
  sets = parsed.sets || [];
} catch(e) {
  throw new Error('ChatGPT yanıtı parse edilemedi: ' + gptResponse.slice(0, 200));
}

return [{
  json: {
    success: true,
    original: { title: originalTitle, tags: originalTags },
    sets
  }
}];
